// Creamos un array vacío donde acumularemos los nuevos items
const out = [];

// MIMEs que consideramos documentos de texto procesables
// Los usaremos para detectar si el email ya trae algún adjunto de tipo documento
const DOC_MIMES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document', // .docx
  'application/msword', // .doc
];

// Recorremos cada item de entrada (normalmente 1 email por ejecución)
for (const inItem of items) {

  // Obtenemos todos los binarios del email (adjuntos)
  // Si no existe la propiedad binary, usamos un objeto vacío
  const binaries = inItem.binary ?? {};

  // Recorremos cada adjunto del email
  for (const [key, bin] of Object.entries(binaries)) {

    // Por cada adjunto generamos un item independiente
    out.push({
      json: {
        // Índice del email dentro de la ejecución (útil para debug)
        sourceEmailIndex: inItem.$index,

        // Nombre original de la key binaria (ej: attachment_0)
        originalKey: key,

        // Nombre del archivo adjunto
        fileName: bin.fileName,

        // Tipo MIME del archivo
        mimeType: bin.mimeType,

        // Tamaño del archivo
        fileSize: bin.fileSize,

        // Datos del email original que arrastramos para contexto
        subject: inItem.json?.subject,
        from: inItem.json?.from,
        date: inItem.json?.date,

        // ID del mensaje en Gmail
        uid: inItem.json?.id,

        // Message-ID del email
        // Gmail simple=false: viene en json.headers["message-id"]
        messageId: inItem.json?.headers?.['message-id'],

        // FIX PAIRED ITEM: Arrastramos html y text completos del email
        // para que nodos posteriores puedan referenciarlos sin perder el pairing
        emailHtml: inItem.json?.html ?? '',
        emailText: inItem.json?.text ?? '',
        emailFrom: inItem.json?.from?.text ?? '',
        emailSubject: inItem.json?.subject ?? '',
      },

      // Renombramos el adjunto a "data"
      // para que los siguientes nodos lo puedan usar de forma estándar
      binary: {
        data: bin,
      },
    });
  }

  // ── NUEVA LÓGICA: FALLBACK AL CUERPO DEL EMAIL ──────────────────────────
  //
  // Problema que resuelve:
  // A veces los remitentes escriben el contenido directamente en el cuerpo
  // del email, sin adjuntar ningún documento (PDF, DOCX, DOC).
  // En ese caso, el bucle anterior no genera ningún item de tipo documento
  // y el flujo se detiene en el IF posterior sin procesar nada.
  //
  // Solución:
  // Si no hay ningún adjunto de tipo documento entre los items generados,
  // construimos un PDF sintético con el cuerpo del email como contenido,
  // sin usar ninguna librería externa (pdfkit no está permitido en n8n).
  // Este item es estructuralmente idéntico a un PDF real, así que entra
  // por la rama PDF del Switch y el resto del flujo lo procesa sin cambios.

  // Miramos si entre todos los items generados hay alguno de tipo documento
  // .some() devuelve true en cuanto encuentra uno que cumpla la condición
  const hasTextDoc = out.some(item =>
    DOC_MIMES.some(mime => (item.json.mimeType || '').toLowerCase().includes(mime))
  );

  // Solo actuamos si NO hay documento de texto entre los adjuntos
  if (!hasTextDoc) {

    // Preferimos el texto plano del email porque ya está limpio
    // Si no existe, usamos el HTML y lo limpiamos nosotros
    const rawText = inItem.json?.text?.trim();
    const rawHtml = inItem.json?.html ?? '';

    // Limpieza básica del HTML para obtener texto legible
    // Eliminamos estilos, scripts, etiquetas y decodificamos entidades comunes
    const bodyText = rawText || rawHtml
      .replace(/<style[\s\S]*?<\/style>/gi, '')   // elimina bloques <style>
      .replace(/<script[\s\S]*?<\/script>/gi, '')  // elimina bloques <script>
      .replace(/<[^>]+>/g, ' ')                    // elimina todas las etiquetas HTML
      .replace(/&nbsp;/g, ' ')                     // espacio no rompible → espacio normal
      .replace(/&amp;/g, '&')                      // & codificado → &
      .replace(/&lt;/g, '<')                       // < codificado → 
      .replace(/&gt;/g, '>')                       // > codificado → >
      .replace(/&quot;/g, '"')                     // " codificado → "
      .replace(/\s{2,}/g, '\n')                    // colapsa espacios múltiples en salto de línea
      .trim();

    // Comprobamos que el cuerpo tiene contenido real y suficiente
    // (mínimo 100 caracteres para evitar emails vacíos o solo con firma)
    if (bodyText && bodyText.length >= 100) {

      // Generamos el nombre del archivo a partir del asunto del email
      // Limpiamos caracteres especiales y acortamos a 60 caracteres
      const syntheticFileName = `cuerpo_email_${(inItem.json?.subject ?? 'sin_asunto')
        .replace(/[^a-zA-Z0-9áéíóúÁÉÍÓÚüÜñÑ\s-]/g, '') // elimina caracteres no permitidos
        .replace(/\s+/g, '_')                            // espacios → guiones bajos
        .substring(0, 60)                                // máximo 60 caracteres
      }.pdf`;

      // ── CONSTRUCCIÓN DEL PDF EN BINARIO PURO ──────────────────────────
      //
      // Un PDF tiene esta estructura básica:
      //   1. Cabecera   → versión del formato
      //   2. Objetos    → fuentes, página, contenido de texto
      //   3. Tabla xref → índice de posiciones de cada objeto en el archivo
      //   4. Trailer    → apunta al objeto raíz del documento
      //
      // No usamos ninguna librería externa: construimos el PDF como string
      // siguiendo la especificación mínima válida del formato PDF 1.4

      // Dividimos el cuerpo en líneas de máximo 90 caracteres
      // PDF no hace word-wrap automático, así que lo gestionamos nosotros
      const lines = [];

      // Añadimos el asunto como primera línea (actúa de título)
      const subject = (inItem.json?.subject ?? 'Sin asunto').substring(0, 100);
      lines.push(subject);
      lines.push(''); // línea en blanco separadora entre título y cuerpo

      // Recorremos palabra a palabra para construir líneas de máximo 90 chars
      const words = bodyText.split(' ');
      let currentLine = '';
      for (const word of words) {

        // Respetamos los saltos de línea explícitos que ya venían en el texto
        const parts = word.split('\n');
        for (let i = 0; i < parts.length; i++) {
          const part = parts[i];

          if ((currentLine + ' ' + part).trim().length > 90) {
            // La línea supera el límite: la guardamos y empezamos una nueva
            lines.push(currentLine.trim());
            currentLine = part;
          } else {
            // Todavía cabe: añadimos la palabra a la línea actual
            currentLine = currentLine ? currentLine + ' ' + part : part;
          }

          // Si había un salto de línea explícito, cerramos la línea aquí
          if (i < parts.length - 1) {
            lines.push(currentLine.trim());
            currentLine = '';
          }
        }
      }
      // Guardamos la última línea que quedara pendiente
      if (currentLine.trim()) lines.push(currentLine.trim());

      // Escapamos caracteres especiales para el formato de strings PDF
      // En PDF los paréntesis y backslash dentro de strings deben escaparse
      // Los caracteres fuera del rango ASCII básico los sustituimos por '?'
      // porque usamos Helvetica que solo cubre el rango Latin-1 básico
      const escapePdf = str => str
        .replace(/\\/g, '\\\\')   // backslash → \\
        .replace(/\(/g, '\\(')    // ( → \(
        .replace(/\)/g, '\\)')    // ) → \)
        .replace(/[^\x20-\x7E]/g, '?'); // caracteres no ASCII → ?

      // Parámetros de layout de la página
      const fontSize = 11;
      const lineHeight = fontSize * 1.4; // interlineado estándar
      const startX = 50;                 // margen izquierdo en puntos tipográficos
      const startY = 780;                // posición Y inicial (PDF mide desde abajo)

      // Construimos las instrucciones de texto en formato PDF
      // BT = Begin Text, ET = End Text
      // Tf = seleccionar fuente y tamaño
      // Td = mover cursor a posición (x, y)
      // Tj = mostrar el string de texto
      let textStream = 'BT\n';
      textStream += `/F1 ${fontSize} Tf\n`; // fuente F1 (Helvetica), tamaño 11

      lines.forEach((line, i) => {
        const y = startY - i * lineHeight;
        // Posicionamos el cursor en coordenadas absolutas para cada línea
        textStream += `${startX} ${y.toFixed(2)} Td\n`;
        textStream += `(${escapePdf(line)}) Tj\n`;
        // Reseteamos la posición al origen para que el siguiente Td sea absoluto
        textStream += `${-startX} ${-y.toFixed(2)} Td\n`;
      });

      textStream += 'ET\n';

      // ── Ensamblamos los objetos PDF ──────────────────────────────────
      // En PDF cada objeto tiene la forma:  N 0 obj ... endobj
      // Guardamos el offset (posición en bytes) de cada objeto
      // para construir la tabla xref al final

      const offsets = [];
      let pdf = '';

      // Cabecera — declara la versión del formato PDF
      pdf += '%PDF-1.4\n';

      // Objeto 1 — Catálogo raíz del documento
      // Es el punto de entrada: apunta al árbol de páginas (objeto 2)
      offsets[1] = pdf.length;
      pdf += '1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n';

      // Objeto 2 — Árbol de páginas
      // Contiene la lista de páginas; aquí solo tenemos una (objeto 3)
      offsets[2] = pdf.length;
      pdf += '2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n';

      // Objeto 3 — La página física
      // MediaBox define el tamaño: 612x792 puntos = tamaño Letter (similar A4)
      // Resources declara la fuente F1 que usaremos (objeto 4)
      // Contents apunta al stream con las instrucciones de texto (objeto 5)
      offsets[3] = pdf.length;
      pdf += '3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] ';
      pdf += '/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>\nendobj\n';

      // Objeto 4 — Declaración de fuente
      // Helvetica es una fuente base de PDF, siempre disponible sin necesidad de embeber
      offsets[4] = pdf.length;
      pdf += '4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n';

      // Objeto 5 — Stream con las instrucciones de dibujo del texto
      // Length es obligatorio: indica cuántos bytes ocupa el contenido del stream
      const streamLength = Buffer.byteLength(textStream, 'latin1');
      offsets[5] = pdf.length;
      pdf += `5 0 obj\n<< /Length ${streamLength} >>\nstream\n`;
      pdf += textStream;
      pdf += 'endstream\nendobj\n';

      // ── Tabla xref ────────────────────────────────────────────────────
      // Índice de posiciones de todos los objetos en el archivo
      // El lector PDF lo usa para saltar directamente a cada objeto
      // sin tener que leer el archivo completo de principio a fin
      const xrefOffset = pdf.length;
      pdf += 'xref\n';
      pdf += '0 6\n'; // 6 entradas: objeto 0 (libre) + objetos 1 al 5
      pdf += '0000000000 65535 f \n'; // objeto 0 siempre libre (requerido por el estándar)
      for (let i = 1; i <= 5; i++) {
        // Cada entrada ocupa exactamente 20 bytes:
        // offset en 10 dígitos + número de generación + estado (n=en uso)
        pdf += `${String(offsets[i]).padStart(10, '0')} 00000 n \n`;
      }

      // ── Trailer ───────────────────────────────────────────────────────
      // Cierra el archivo: apunta al catálogo raíz y declara
      // la posición en bytes donde empieza la tabla xref
      pdf += 'trailer\n<< /Size 6 /Root 1 0 R >>\n';
      pdf += `startxref\n${xrefOffset}\n%%EOF\n`;

      // Convertimos el string PDF a Base64 usando latin1
      // IMPORTANTE: usamos latin1 (no utf8) porque latin1 mapea 1 char = 1 byte
      // exactamente, lo que garantiza que los offsets del xref sean correctos.
      // Con utf8, los caracteres especiales ocuparían 2+ bytes y el PDF quedaría corrupto.
      const base64Pdf = Buffer.from(pdf, 'latin1').toString('base64');

      // Añadimos el item sintético con mimeType PDF
      // Es estructuralmente idéntico a un adjunto PDF real
      out.push({
        json: {
          // Mismos campos de contexto que los items de adjuntos reales
          sourceEmailIndex: inItem.$index,
          originalKey: 'email_body_synthetic', // clave especial, útil para debug
          fileName: syntheticFileName,
          mimeType: 'application/pdf', // entra por la rama PDF del Switch sin cambios
          fileSize: pdf.length,
          subject: inItem.json?.subject,
          from: inItem.json?.from,
          date: inItem.json?.date,
          uid: inItem.json?.id,
          messageId: inItem.json?.headers?.['message-id'],
          emailHtml: inItem.json?.html ?? '',
          emailText: inItem.json?.text ?? '',
          emailFrom: inItem.json?.from?.text ?? '',
          emailSubject: inItem.json?.subject ?? '',

          // Flag para identificar este item como generado artificialmente
          // Útil si en el futuro quieres tratarlo diferente en algún nodo
          isSyntheticFromEmailBody: true,
        },

        // Binario PDF listo para que n8n lo trate igual que cualquier adjunto PDF real
        binary: {
          data: {
            data: base64Pdf,          // contenido del PDF en Base64
            mimeType: 'application/pdf',
            fileName: syntheticFileName,
            fileExtension: 'pdf',
          },
        },
      });

      // Si bodyText tiene menos de 100 caracteres no generamos item sintético
      // y el email se descartará en el IF posterior (comportamiento correcto:
      // un email sin adjuntos y sin cuerpo real no tiene contenido procesable)
    }
  }
  // ── FIN FALLBACK ─────────────────────────────────────────────────────────
}

// Devolvemos un item por cada adjunto encontrado
// (o el PDF sintético del cuerpo si no había documentos adjuntos)
return out;

// Ordenar poniendo PDFs primero
const sorted = items.sort((a, b) => {
  const aIsPdf = (a.json.mimeType || '').includes('application/pdf');
  const bIsPdf = (b.json.mimeType || '').includes('application/pdf');
  if (aIsPdf && !bIsPdf) return -1;
  if (!aIsPdf && bIsPdf) return 1;
  return 0;
});

// Devolver solo el primero
return [sorted[0]];

