const record = $('Get a record').first().json;

// Airtable multi-select returns arrays; single-select returns string
const toArray = val => Array.isArray(val) ? val : (val ? [val] : []);

const categoríasNAE = toArray(record['Categoría NAE']);
const categoríasESG = toArray(record['Categoría ESG']);
const categoríasODS = toArray(record['Categoría ODS']);

const mapNAE = {
  'Noticias': 218,
  'Opinión': 144,
  'Entrevistas': 118
};

const mapESG = {
  'Medioambiente': 6,
  'Social': 13,
  'Buen gobierno': 12
};

const mapODS = {
  'ODS 1 Fin de la pobreza': 4,
  'ODS 2 Hambre cero': 5,
  'ODS 3 Salud y bienestar': 129,
  'ODS 4 Educación de calidad': 130,
  'ODS 5 Igualdad de género': 131,
  'ODS 6 Agua limpia y saneamiento': 132,
  'ODS 7 Energía asequible y no contaminante': 133,
  'ODS 8 Trabajo decente y crecimiento económico': 134,
  'ODS 9 Industria, innovación e infraestructura': 135,
  'ODS 10 Reducción de las desigualdades': 136,
  'ODS 11 Ciudades y comunidades sostenibles': 137,
  'ODS 12 Producción y consumo responsables': 138,
  'ODS 13 Acción por el clima': 139,
  'ODS 14 Vida submarina': 140,
  'ODS 15 Vida de ecosistemas terrestres': 141,
  'ODS 16 Paz, justicia e instituciones sólidas': 142,
  'ODS 17 Alianzas para lograr los objetivos': 143
};

const categories = [
  ...categoríasNAE.map(v => mapNAE[v]).filter(id => id !== undefined),
  ...categoríasESG.map(v => mapESG[v]).filter(id => id !== undefined),
  ...categoríasODS.map(v => mapODS[v]).filter(id => id !== undefined),
];

return [{ json: { categories } }];

const record = $('Get a record').first().json;
const postId = $('Create a Post').first().json.id;
const categories = $('Map — Categorías a IDs WordPress').first().json.categories;

const subtitulo = record['Subtítulo'] ?? '';
const description = record['Description'] ?? '';
const excerpt = record['Extracto'] ?? '';
const rawHighlights = record['Highlights'] ?? '';

const highlights = rawHighlights
  .split('|')
  .map(h => h.trim())
  .filter(h => h.length > 0)
  .map(h => ({ point: h }));

const WP_API_URL = 'https://www.corresponsables.com/wp-json/wp/v2';
const AUTH = { username: $env.WP_USER, password: $env.WP_PASSWORD };

const res1 = await this.helpers.httpRequest({
  method: 'POST',
  url: `${WP_API_URL}/posts/${postId}`,
  body: { tagline: subtitulo, highlights: highlights, excerpt: excerpt },
  auth: AUTH,
  json: true,
  ignoreHttpStatusErrors: true
});

const res2 = await this.helpers.httpRequest({
  method: 'POST',
  url: `${WP_API_URL}/posts/${postId}`,
  body: { categories: categories },
  auth: AUTH,
  json: true,
  ignoreHttpStatusErrors: true
});

const res3 = await this.helpers.httpRequest({
  method: 'POST',
  url: `${WP_API_URL}/posts/${postId}`,
  body: { 
    meta: { 
      _yoast_wpseo_metadesc: description,
      _yoast_wpseo_primary_category: categories[0]
    } 
  },
  auth: AUTH,
  json: true,
  ignoreHttpStatusErrors: true
});

return [{ json: {
  postId,
  tagline: res1.tagline,
  highlights: res1.highlights,
  excerpt: res1.excerpt,
  categories: res2.categories,
  yoast_metadesc: res3.meta?._yoast_wpseo_metadesc,
  yoast_primary: res3.meta?._yoast_wpseo_primary_category,
  meta_completo: res3.meta
}}];

// Get a record con downloadFields devuelve la imagen con una clave dinámica
// (ej: "Imagen WP_0"). La renombramos a 'data' para que Upload IMG to WP Media la encuentre.
const item = items[0];
const binaries = item.binary ?? {};

// Buscar la primera clave que contenga imagen
const imgKey = Object.keys(binaries).find(k => 
  binaries[k].mimeType?.startsWith('image/') || k.toLowerCase().includes('imagen')
) ?? Object.keys(binaries)[0];

if (!imgKey) {
  throw new Error('No se encontró imagen binaria en el item de Airtable');
}

return [{
  json: {
    ...item.json,
    _imgFileName: binaries[imgKey].fileName,
    _imgMimeType: binaries[imgKey].mimeType,
  },
  binary: {
    data: binaries[imgKey]  // renombrar a 'data'
  }
}];

